class UserRole(enum.Enum):
    user = 'user'
    moderator = 'moderator'
    admin = 'admin'

class AccountStatus(enum.Enum):
    active = 'active'
    suspended = 'suspended'

class SubscriptionTier(enum.Enum):
    free = 'free'
    pro = 'pro'
    enterprise = 'enterprise'

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(SQLEnum(UserRole), default=UserRole.user, nullable=False)
    account_status = db.Column(SQLEnum(AccountStatus), default=AccountStatus.active, nullable=False)
    subscription_tier = db.Column(SQLEnum(SubscriptionTier), default=SubscriptionTier.free, nullable=False)

