class UserUpdate(flask_restful.Resource):
    def put(self, user_id):
        if current_user.role != 'admin':
            return {'message': 'Unauthorized: Only administrators can update user records.'}, 403

        user = User.query.get(user_id)
        if not user:
            return {'message': 'User not found.'}, 404

        data = request.get_json()
        if not data:
            return {'message': 'No input data provided.'}, 400

        # Fields that can be updated by an admin
        updatable_fields = {
            'username': str,
            'email': str,
            'role': UserRole,
            'account_status': AccountStatus,
            'subscription_tier': SubscriptionTier
        }

        for field, field_type in updatable_fields.items():
            if field in data:
                value = data[field]
                try:
                    if field_type in [UserRole, AccountStatus, SubscriptionTier]:
                        # Convert string value to Enum member
                        setattr(user, field, field_type(value))
                    else:
                        # For string fields like username, email
                        setattr(user, field, field_type(value))
                except ValueError:
                    return {'message': f'Invalid value for {field}: {value}.'}, 400
                except Exception as e:
                    return {'message': f'Error updating {field}: {str(e)}'}, 400

        try:
            db.session.commit()
            return {'message': 'User updated successfully.', 'user': user.to_dict()}, 200
        except Exception as e:
            db.session.rollback()
            return {'message': f'Database error: {str(e)}'}, 500

api.add_resource(UserUpdate, '/api/users/<int:user_id>')

